mapper.select:
SELECT id, member_id, course_id, status, create_time, cancel_time
FROM reservation
WHERE id = #{id}

SELECT r.id, r.member_id, r.course_id, r.status, r.create_time, r.cancel_time, m.real_name AS member_name, m.username AS member_username, c.name AS course_name, c.coach AS course_coach, c.schedule_time AS course_schedule_time, c.location AS course_location FROM reservation r LEFT JOIN member m ON r.member_id = m.id LEFT JOIN course c ON r.course_id = c.id
AND r.member_id = #{memberId}
AND r.course_id = #{courseId}
AND r.status = #{status}
ORDER BY r.create_time DESC

SELECT r.id, r.member_id, r.course_id, r.status, r.create_time, r.cancel_time,
       m.real_name AS member_name, m.username AS member_username,
       c.name AS course_name, c.coach AS course_coach,
       c.schedule_time AS course_schedule_time, c.location AS course_location
FROM reservation r
LEFT JOIN member m ON r.member_id = m.id
LEFT JOIN course c ON r.course_id = c.id


        AND r.member_id = #{memberId}


        AND r.course_id = #{courseId}


        AND r.status = #{status}


ORDER BY r.create_time DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(*)
FROM reservation r


        AND r.member_id = #{memberId}


        AND r.course_id = #{courseId}


        AND r.status = #{status}
